import{_ as e,o as t,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"MCP / SSH / WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"features/mcp-ssh-webdav.md","filePath":"features/mcp-ssh-webdav.md"}'),i={name:"features/mcp-ssh-webdav.md"};function r(o,a,n,d,c,h){return t(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="mcp-ssh-webdav" tabindex="-1">MCP / SSH / WebDAV <a class="header-anchor" href="#mcp-ssh-webdav" aria-label="Permalink to &quot;MCP / SSH / WebDAV&quot;">​</a></h1><p>Lyra Code 通过三大协议集成远程服务，所有连接均可通过统一的自然语言界面完成配置。</p><h2 id="mcp-模型上下文协议" tabindex="-1">MCP（模型上下文协议） <a class="header-anchor" href="#mcp-模型上下文协议" aria-label="Permalink to &quot;MCP（模型上下文协议）&quot;">​</a></h2><p>连接远程 MCP 服务器，扩展 Agent 的能力边界：</p><ul><li><strong>Streamable HTTP</strong> 传输</li><li><strong>SSE（Server-Sent Events）</strong> 传输</li><li>随时添加、配置、启用和禁用服务器</li><li>每个 MCP 工具以 <code>mcp_</code> 前缀标识，清晰可辨</li></ul><h3 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h3><ul><li>接入专业 AI 工具和数据源</li><li>通过 MCP 封装集成外部 API</li><li>无需修改应用即可扩展 Lyra Code 的原生能力</li></ul><div class="tip custom-block"><p class="custom-block-title">MCP 工具</p><p>MCP 服务器的工具与原生工具并列显示。所有 MCP 工具调用均需要<strong>用户确认</strong>后才能执行。</p></div><h2 id="ssh" tabindex="-1">SSH <a class="header-anchor" href="#ssh" aria-label="Permalink to &quot;SSH&quot;">​</a></h2><p>安全连接远程服务器，进行运维管理和自动化操作：</p><h3 id="支持的目标" tabindex="-1">支持的目标 <a class="header-anchor" href="#支持的目标" aria-label="Permalink to &quot;支持的目标&quot;">​</a></h3><ul><li><strong>Linux</strong> 服务器</li><li><strong>Windows</strong> 服务器</li><li><strong>Git</strong> 服务器</li></ul><h3 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h3><ul><li>密码登录</li><li>私钥认证（可选口令短语）</li></ul><h3 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h3><ul><li>远程执行命令并获取 <code>stdout</code>/<code>stderr</code></li><li>每次会话可指定工作目录</li><li>为交互式命令提供输入行（如 Y/N 提示）</li><li>可配置超时</li></ul><h3 id="安全机制" tabindex="-1">安全机制 <a class="header-anchor" href="#安全机制" aria-label="Permalink to &quot;安全机制&quot;">​</a></h3><ul><li>每条 SSH 命令都需要<strong>用户明确批准</strong></li><li>执行前完整预览命令</li><li>使用 <code>list_ssh_servers</code> 查看已配置连接</li><li>安装或修改软件前务必先检查系统资源</li></ul><h2 id="webdav" tabindex="-1">WebDAV <a class="header-anchor" href="#webdav" aria-label="Permalink to &quot;WebDAV&quot;">​</a></h2><p>通过 WebDAV 访问和管理远程存储：</p><h3 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><code>webdav_list</code></td><td>使用 PROPFIND 浏览目录</td></tr><tr><td><code>webdav_search</code></td><td>按文件名或路径搜索</td></tr><tr><td><code>webdav_download</code></td><td>下载文件到工作区</td></tr><tr><td><code>webdav_upload</code></td><td>上传工作区文件到服务器</td></tr></tbody></table><h3 id="云备份" tabindex="-1">云备份 <a class="header-anchor" href="#云备份" aria-label="Permalink to &quot;云备份&quot;">​</a></h3><ul><li>直接导出备份到 WebDAV</li><li>默认路径：<code>/LyraCode/lyra_backup_latest.zip</code></li><li>导入时自动检测最新备份</li><li>支持完整和选择性备份（方案、对话、配置、密钥）</li></ul><h2 id="自然语言配置管理" tabindex="-1">自然语言配置管理 <a class="header-anchor" href="#自然语言配置管理" aria-label="Permalink to &quot;自然语言配置管理&quot;">​</a></h2><p>所有 MCP、SSH、WebDAV、技能包和 Agent 工具配置都可以通过自然语言管理：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;在 https://my-mcp.example.com 添加一个 Streamable HTTP 的 MCP 服务器&quot;</span></span>
<span class="line"><span>&quot;配置 SSH 连接到我的 VPS，IP 是 192.168.1.100，使用密钥认证&quot;</span></span>
<span class="line"><span>&quot;设置 WebDAV 备份到我的 NextCloud 服务器&quot;</span></span>
<span class="line"><span>&quot;启用设备硬件检测工具&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>你只需描述需求，Agent 会处理配置细节。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>HTTP API、MCP 和 WebDAV 端点若非 HTTPS 或受信网络保护，则<strong>不安全</strong>。生产环境请务必使用加密连接。</p></div>`,29)])])}const b=e(i,[["render",r]]);export{u as __pageData,b as default};
